import{_ as a,o as i,c as o,ag as r}from"./chunks/framework.ByAj6Cie.js";const u=JSON.parse('{"title":"Fundamentos de termografía","description":"","frontmatter":{},"headers":[],"relativePath":"es/tools/measurement/thermography-basics.md","filePath":"es/tools/measurement/thermography-basics.md"}'),n={name:"es/tools/measurement/thermography-basics.md"};function s(t,e,l,c,d,m){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="fundamentos-de-termografia" tabindex="-1">Fundamentos de termografía <a class="header-anchor" href="#fundamentos-de-termografia" aria-label="Permalink to &quot;Fundamentos de termografía&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>La termografía es la técnica de analizar patrones de temperatura utilizando imágenes infrarrojas.</p><p>Permite detectar anomalías térmicas que indican posibles problemas en sistemas eléctricos, mecánicos o de proceso. Se utiliza ampliamente como herramienta de diagnóstico en mantenimiento e inspección.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>El propósito de la termografía es:</p><ul><li>Identificar condiciones de temperatura anormales</li><li>Detectar signos tempranos de falla del equipo</li><li>Respaldar el mantenimiento preventivo y predictivo</li><li>Mejorar la seguridad al identificar riesgos de sobrecalentamiento</li></ul><p>Proporciona información sobre el estado del sistema sin interrumpir la operación.</p><h2 id="como-funciona" tabindex="-1">Cómo funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo funciona&quot;">​</a></h2><p>La termografía utiliza cámaras infrarrojas para capturar la distribución de temperatura en superficies.</p><p>El proceso involucra:</p><ul><li>Detectar la radiación infrarroja emitida por los objetos</li><li>Convertir la radiación en valores de temperatura</li><li>Mostrar los resultados como una imagen térmica</li></ul><p>El análisis se centra en identificar diferencias de temperatura en lugar de valores absolutos.</p><p>Los factores clave que afectan la medición incluyen:</p><ul><li>Emisividad de la superficie</li><li>Condiciones ambientales</li><li>Condiciones de carga durante la medición</li></ul><p>Los patrones térmicos se interpretan para determinar si una condición es normal o anormal.</p><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>La termografía se utiliza en:</p><ul><li>Inspecciones eléctricas de tableros de control y conexiones</li><li>Monitoreo de motores, rodamientos y sistemas mecánicos</li><li>Detección de problemas de aislamiento</li><li>Evaluación de la distribución de temperatura en procesos</li><li>Programas de mantenimiento preventivo</li></ul><p>Es común en sistemas industriales, comerciales e infraestructura.</p><h2 id="consideraciones-clave" tabindex="-1">Consideraciones clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones clave&quot;">​</a></h2><ul><li>La interpretación requiere comprensión del comportamiento del sistema</li><li>Las diferencias de temperatura suelen ser más importantes que los valores exactos</li><li>Los factores ambientales pueden influir en las lecturas</li><li>Las mediciones deben tomarse bajo condiciones operativas normales</li><li>Los métodos de inspección consistentes mejoran la confiabilidad</li></ul><p>La interpretación incorrecta puede conducir a diagnósticos erróneos.</p><h2 id="notas-practicas" tabindex="-1">Notas prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas prácticas&quot;">​</a></h2><ul><li>Comparar componentes similares bajo condiciones de carga similares</li><li>Establecer mediciones de referencia base</li><li>Centrarse en tendencias a lo largo del tiempo en lugar de mediciones individuales</li><li>Combinar la termografía con otros métodos de diagnóstico</li><li>Documentar los hallazgos con imágenes y contexto</li></ul><p>La termografía es eficaz cuando se utiliza como herramienta de diagnóstico comparativa y basada en tendencias.</p>',26)])])}const f=a(n,[["render",s]]);export{u as __pageData,f as default};
